import{_ as t,o as i,c as a,a6 as r}from"./chunks/framework.DtxWasON.js";const o="/assets/mainchain/ibc/web-portal/1.chain-select.png",n="/assets/mainchain/ibc/web-portal/2.chain-select-dropdown-options.png",s="/assets/mainchain/ibc/web-portal/3.connect-to-unification.png",p="/assets/mainchain/ibc/web-portal/4.approve-keplr-add-unification.png",c="/assets/mainchain/ibc/web-portal/5.unification-added-1.png",l="/assets/mainchain/ibc/web-portal/6.unification-added-2.png",d="/assets/mainchain/ibc/web-portal/7.unification-gravity-begin-transfer.png",h="/assets/mainchain/ibc/web-portal/8.unification-gravity-starting-transfer.png",g="/assets/mainchain/ibc/web-portal/9.unification-keplr-approve.png",m="/assets/mainchain/ibc/web-portal/10.transfer-started.png",f="/assets/mainchain/ibc/web-portal/11.unification-transfer-complete.png",b="/assets/mainchain/ibc/web-portal/12.unification-gravity-tx-history.png",u="/assets/mainchain/ibc/web-portal/13.connect-metamask.png",w="/assets/mainchain/ibc/web-portal/14.gravity-ethereum-begin.png",y="/assets/mainchain/ibc/web-portal/15.gravity-ethereum-approve-1.png",v="/assets/mainchain/ibc/web-portal/16.gravity-ethereum-approve-2.png",_="/assets/mainchain/ibc/web-portal/17.batch-transaction-created.png",k="/assets/mainchain/ibc/web-portal/18.add-suggested-token.png",U="/assets/mainchain/ibc/web-portal/19.gravity-ethereum-tx-history.png",B="/assets/mainchain/ibc/web-portal/20.fund-in-metamask.png",D="/assets/mainchain/ibc/web-portal/21-ethereum-gravity-begin.png",F="/assets/mainchain/ibc/web-portal/22.select-fund-token.png",T="/assets/mainchain/ibc/web-portal/23.approve-fund-1.png",N="/assets/mainchain/ibc/web-portal/24.approve-fund-2.png",x="/assets/mainchain/ibc/web-portal/25.fund-approve-complete.png",C="/assets/mainchain/ibc/web-portal/26.permission-given.png",G="/assets/mainchain/ibc/web-portal/27.check-approval.png",A="/assets/mainchain/ibc/web-portal/28.confirm-tx-metamask.png",q="/assets/mainchain/ibc/web-portal/29.ethereum-gravity-tx-started.png",E="/assets/mainchain/ibc/web-portal/30.ethereum-gravity-tx-history.png",P="/assets/mainchain/ibc/web-portal/31.gravity-unification-begin.png",M="/assets/mainchain/ibc/web-portal/32.gravity-ethereum-tx-history.png",$=JSON.parse('{"title":"IBC Transfer to Gravity Bridge via Web Portal","description":"","frontmatter":{},"headers":[],"relativePath":"mainchain/ibc/gravity-bridge/web-portal.md","filePath":"mainchain/ibc/gravity-bridge/web-portal.md"}'),S={name:"mainchain/ibc/gravity-bridge/web-portal.md"};function K(I,e,O,H,W,R){return i(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="ibc-transfer-to-gravity-bridge-via-web-portal" tabindex="-1">IBC Transfer to Gravity Bridge via Web Portal <a class="header-anchor" href="#ibc-transfer-to-gravity-bridge-via-web-portal" aria-label="Permalink to &quot;IBC Transfer to Gravity Bridge via Web Portal&quot;">​</a></h1><div class="tip custom-block"><p class="custom-block-title">Note</p><p>Refer to the official Blockscape Gravity Portal <a href="https://blockscape-network.medium.com/a-beginners-guide-when-and-how-to-use-the-gravity-bridge-portal-97d5745025dd" target="_blank" rel="noreferrer">HowTo</a> for generic usage</p></div><p><strong>Originally published on <a href="https://medium.com/unificationfoundation/wfund-bridge-access-use-grow-evolve-54adb2aabf70" target="_blank" rel="noreferrer">Medium</a></strong></p><p>This guide will cover sending FUND from Unification over IBC to the ERC20 wFUND contract on Ethereum mainnet, and back again via the Web Portal. The guide assumes any wallets the reader has (Unification, Gravity Bridge and Ethereum) are sufficiently funded to cover any gas fees on the respective chains in addition to the FUND being transferred.</p><h2 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to &quot;Introduction&quot;">​</a></h2><p>Bridging FUND to wFUND (and vice versa) will require a Unification wallet within Keplr which can be used alongside the Unification main Web Wallet</p><p>The Keplr wallet can be downloaded through the following link: <a href="https://www.keplr.app/download" target="_blank" rel="noreferrer">https://www.keplr.app/download</a></p><p>Once the Keplr wallet is installed &amp; backed up, we can start the process through the Gravity Bridge portal (Your Keplr Unification wallet can be recovered in the Unification Web wallet if desired)</p><p>This can be done by accessing the &quot;Use Gravity Bridge Here&quot; link at <a href="https://www.gravitybridge.net/" target="_blank" rel="noreferrer">https://www.gravitybridge.net/</a></p><p>Alternatively the link can be accessed directly from</p><p>Gravity Bridge Portal: <a href="https://bridge.blockscape.network/" target="_blank" rel="noreferrer">https://bridge.blockscape.network/</a></p><p>It&#39;s important to note that bridging FUND to wFUND is a two-step process:</p><ol><li>Unification &lt;-&gt; Gravity Bridge</li><li>Gravity Bridge &lt;-&gt; Ethereum</li></ol><p>Together, we&#39;ll review/break down each step of this process.</p><h2 id="fund-gt-erc-20" tabindex="-1">FUND -&gt; ERC-20 <a class="header-anchor" href="#fund-gt-erc-20" aria-label="Permalink to &quot;FUND -&amp;gt; ERC-20&quot;">​</a></h2><h3 id="_1-bridge-fund-from-unification-to-gravity-bridge" tabindex="-1">1. Bridge FUND from Unification to Gravity Bridge <a class="header-anchor" href="#_1-bridge-fund-from-unification-to-gravity-bridge" aria-label="Permalink to &quot;1. Bridge FUND from Unification to Gravity Bridge&quot;">​</a></h3><p>To start to bridge Fund from Unification to Ethereum, we will initially click on the drop-down to open the menu/connect the Keplr wallets</p><p><img src="'+o+'" alt="Chain Select" title="Chain Select"></p><p>In the dropdown, select Unification:</p><p><img src="'+n+'" alt="Chain Select" title="Chain Select"></p><p>And once selected, press &quot;connect&quot;</p><p><img src="'+s+'" alt="Connect to Unification" title="Connect to Unification"></p><p>This will prompt Keplr to add Unification to your Kepler wallet</p><p>You should see the following prompt and accept it. As previously noted, this will carry the needed parameters for a successful transfer in future steps.</p><p><img src="'+p+'" alt="Approve Keplr" title="Approve Keplr"></p><p>Once accepted, this action will add the Unification wallet in the bottom of the list, which you can confirm by scrolling down</p><p><img src="'+c+'" alt="Unification added" title="Unification added"></p><p><img src="'+l+'" alt="Unification added" title="Unification added"></p><p>Congratulations! You are now ready to start the first step of the bridge!</p><div class="tip custom-block"><p class="custom-block-title">Note</p><p>If you have an existing connection to Unification in Keplr and are having issues connecting, you can delete the configuration from Keplr (reference the circled &quot;unification (x)&quot; in image above), and follow the previous steps to re-add it.</p></div><p>Once both networks are selected, (assuming you have transferred funds to the wallet) you can simply select the amount of FUND and hit &quot;Begin Transfer&quot;</p><p><img src="'+d+'" alt="Begin Transfer" title="Begin Transfer"></p><p>When executed, you will see the following prompt</p><p><img src="'+h+'" alt="Start Transfer" title="Start Transfer"></p><p>The action should prompt a call in your wallet which you can approve:</p><p><img src="'+g+'" alt="Approve Keplr" title="Approve Keplr"></p><p>Once accepted, you will see a confirmation message</p><p><img src="'+m+'" alt="Transfer Started" title="Transfer Started"></p><p>If executed correctly, this step will be fairly quick and result in a confirmation message similar to below:</p><p><img src="'+f+'" alt="Transfer Complete" title="Transfer Complete"></p><p>And the status of the transaction will show in the transaction history once the ticket is confirmed which will change to a green check after the fully processed</p><p><img src="'+b+'" alt="Tx History" title="Tx History"></p><p>Congratulations! You have successfully bridged your FUND to Gravity Bridge and are ready to start the second step of the process to wFUND/Ethereum!</p><h3 id="_2-bridge-fund-from-gravity-bridge-to-ethereum" tabindex="-1">2. Bridge FUND from Gravity Bridge to Ethereum <a class="header-anchor" href="#_2-bridge-fund-from-gravity-bridge-to-ethereum" aria-label="Permalink to &quot;2. Bridge FUND from Gravity Bridge to Ethereum&quot;">​</a></h3><p>Now that we are familiar with Gravity Bridge, the steps of this process will be rather simple/familiar.</p><p>Once ethereum is chosen as the destination, you will need to connect your metamask account to the site as normal:</p><p><img src="'+u+'" alt="Connect MetaMask" title="Connect MetaMask"></p><p>Following this step, we select Gravity Bridge as the source and Ethereum as the destination, enter the amount of FUND to transfer and the desired bridge fee option</p><p><img src="'+w+'" alt="Begin Gravity" title="Begin gravity"></p><p>The only additional point of consideration will be the speed of the transfers</p><p>As transfers are batched in different stages, the timing of the transfers is an estimate.</p><p>In our experience so far, standard transfer has been slightly faster than the estimate and the Instant, slightly less!</p><p>Once confirmed, you will see a notification similar to below, which you can approve</p><p><img src="'+y+'" alt="Approve Keplr" title="Approve Keplr"></p><p>Once approved, another wallet call will be made to approve:</p><p><img src="'+v+'" alt="Approve Keplr" title="Approve Keplr"></p><p>Followed by a confirmation of the batch</p><p><img src="'+_+'" alt="Tx Created" title="Tx Created"></p><p>At this point, you can add FUND to your Metamask wallet for easier access</p><p><img src="'+k+'" alt="MetaMask Suggest Token" title="MetaMask Suggest Token"></p><p>The status of your transaction can be seen on the Gravity Bridge Transactions pages at <a href="https://bridge.blockscape.network/history" target="_blank" rel="noreferrer">https://bridge.blockscape.network/history</a></p><p><img src="'+U+'" alt="Tx History" title="Tx History"></p><p>and once completed, the FUND will reflect in your Metamask Wallet!</p><p><img src="'+B+'" alt="FUND in MetaMask" title="FUND in MetaMask"></p><p>Congrats! Your FUND has officially arrived and is ready to use on Ethereum!</p><h2 id="erc-20-gt-fund" tabindex="-1">ERC-20 -&gt; FUND <a class="header-anchor" href="#erc-20-gt-fund" aria-label="Permalink to &quot;ERC-20 -&amp;gt; FUND&quot;">​</a></h2><p>Bridging wFUND back to FUND will follow the reverse of the same process described above</p><p>Ethereum -&gt; Gravity Bridge -&gt; Unification</p><h3 id="_1-bridge-from-wfund-to-gravity-bridge" tabindex="-1">1. Bridge from wFUND to Gravity Bridge <a class="header-anchor" href="#_1-bridge-from-wfund-to-gravity-bridge" aria-label="Permalink to &quot;1. Bridge from wFUND to Gravity Bridge&quot;">​</a></h3><p>Starting at the Blockspace portal, we can simply choose our wallet for Eth+ GB</p><p><img src="'+D+'" alt="Begin" title="Begin"></p><p>To find FUND, you can search by the contract address below:</p><p><code>0xe9B076B476D8865cDF79D1Cf7DF420EE397a7f75</code></p><p>And confirm on etherscan at</p><p><a href="https://etherscan.io/token/0xe9B076B476D8865cDF79D1Cf7DF420EE397a7f75" target="_blank" rel="noreferrer">https://etherscan.io/token/0xe9B076B476D8865cDF79D1Cf7DF420EE397a7f75</a></p><p><img src="'+F+'" alt="Select FUND" title="Select FUND"></p><p>Once FUND is selected, You will need to give permission to access FUND through the following two prompts</p><p><img src="'+T+'" alt="Approve" title="Approve"><img src="'+N+'" alt="Approve" title="Approve"></p><p>With the approval processed, you will be able to start the transfer</p><p><img src="'+x+'" alt="Approve Complete" title="Approve Complete"><img src="'+C+'" alt="Permission Given" title="Permission Given"><img src="'+G+'" alt="Check Approve" title="Check Approve"></p><p>Finally you will approve the transaction in your Metamask wallet:</p><p><img src="'+A+'" alt="Confirm MetaMask" title="Confirm MetaMask"></p><p>And when processed, a confirmation similar to the one below will appear:</p><p><img src="'+q+'" alt="Tx Started" title="Tx Started"></p><p>Now is another good time to go for a coffee, and once returned your transaction should show completed as indicated by the checkmark in the status page and the FUND back in your GB wallet. At the time of writing, the transaction should be complete in 96 block confirmations.</p><p><img src="'+E+'" alt="Tx History" title="Tx History"></p><h3 id="_2-fund-from-gravity-bridge-to-unification" tabindex="-1">2. FUND from Gravity Bridge to Unification <a class="header-anchor" href="#_2-fund-from-gravity-bridge-to-unification" aria-label="Permalink to &quot;2. FUND from Gravity Bridge to Unification&quot;">​</a></h3><p>The process of this transfer is identical to our first transfer with Gravity Bridge selected as the source and Unification as the destination</p><p><img src="'+P+'" alt="Begin" title="Begin"></p><p>Once completed, your FUND will once again be visible in your Unification wallet and exchangeable to your Unification web wallet if desired!</p><p><img src="'+M+'" alt="Tx History" title="Tx History"></p>',91)])])}const V=t(S,[["render",K]]);export{$ as __pageData,V as default};
